import java.io.IOException;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = sanitizeUserInput(userInput);

        // Output sanitized user input in the response
        response.getWriter().println("<h1>Hello " + sanitizedInput + "</h1>");
    }

    private String sanitizeUserInput(String userInput) {
        // Implement proper input sanitization based on your application's requirements.
        // For a basic example, you can use an HTML escaping library like OWASP Java Encoder:
        return org.owasp.encoder.Encode.forHtml(userInput);
    }
}

